package org.apache.commons.csv;

import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

import static org.junit.jupiter.api.Assertions.*;

class CSVFormatTest {

    @Test
    void testIsCommentMarkerSet_whenCommentMarkerIsNull() throws Exception {
        // Create a new CSVFormat instance with commentMarker null using withCommentMarker(null)
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker((Character) null);

        assertFalse(format.isCommentMarkerSet());
    }

    @Test
    void testIsCommentMarkerSet_whenCommentMarkerIsSet() throws Exception {
        // Create a new CSVFormat instance with commentMarker set to '#'
        CSVFormat format = CSVFormat.DEFAULT.withCommentMarker('#');

        assertTrue(format.isCommentMarkerSet());
    }
}
